// MARK: - Token Storage

protocol TokenStorageProtocol {
    var accessToken: String? { get set }
    var refreshToken: String? { get set }
    func clearTokens()
}

final class KeychainTokenStorage: TokenStorageProtocol {
    private let accessTokenKey = "com.example.app.accessToken"
    private let refreshTokenKey = "com.example.app.refreshToken"
    
    var accessToken: String? {
        get { read(key: accessTokenKey) }
        set {
            if let value = newValue {
                save(key: accessTokenKey, value: value)
            } else {
                delete(key: accessTokenKey)
            }
        }
    }
    
    var refreshToken: String? {
        get { read(key: refreshTokenKey) }
        set {
            if let value = newValue {
                save(key: refreshTokenKey, value: value)
            } else {
                delete(key: refreshTokenKey)
            }
        }
    }
    
    func clearTokens() {
        accessToken = nil
        refreshToken = nil
    }
    
    private func save(key: String, value: String) {
        guard let data = value.data(using: .utf8) else { return }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
        
        let addQuery: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        SecItemAdd(addQuery as CFDictionary, nil)
    }
    
    private func read(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    private func delete(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Network Client Protocol

protocol NetworkClientProtocol {
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable?,
        queryItems: [URLQueryItem]?,
        requiresAuth: Bool
    ) async throws -> T
}

// MARK: - Network Client

final class NetworkClient: NetworkClientProtocol {
    
    static let shared = NetworkClient()
    
    private let session: URLSession
    private let environment: Environment
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    var tokenStorage: TokenStorageProtocol
    
    private var isRefreshing = false
    private let refreshLock = NSLock()
    
    init(
        environment: Environment = .development,
        tokenStorage: TokenStorageProtocol = KeychainTokenStorage(),
        sessionConfiguration: URLSessionConfiguration = .default
    ) {
        self.environment = environment
        self.tokenStorage = tokenStorage
        self.decoder = JSONDecoder()
        self.encoder = JSONEncoder()
        
        sessionConfiguration.timeoutIntervalForRequest = 30
        sessionConfiguration.timeoutIntervalForResource = 60
        sessionConfiguration.requestCachePolicy = .reloadIgnoringLocalCacheData
        self.session = URLSession(configuration: sessionConfiguration)
    }
    
    // MARK: - Core Request Method
    
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable? = nil,
        queryItems: [URLQueryItem]? = nil,
        requiresAuth: Bool = true
    ) async throws -> T {
        let urlRequest = try buildRequest(
            endpoint: endpoint,
            body: body,
            queryItems: queryItems,
            requiresAuth: requiresAuth
        )
        
        do {
            let (data, response) = try await session.data(for: urlRequest)
            
            guard let httpResponse = response as? HTTPURLResponse else {
                throw NetworkError.unknown
            }
            
            // Handle 401 - attempt token refresh
            if httpResponse.statusCode == 401 && requiresAuth {
                try await refreshAccessToken()
                // Retry the original request with new token
                let retryRequest = try buildRequest(
                    endpoint: endpoint,
                    body: body,
                    queryItems: queryItems,
                    requiresAuth: requiresAuth
                )
                let (retryData, retryResponse) = try await session.data(for: retryRequest)
                guard let retryHTTPResponse = retryResponse as? HTTPURLResponse else {
                    throw NetworkError.unknown
                }
                return try handleResponse(data: retryData, response: retryHTTPResponse)
            }
            
            return try handleResponse(data: data, response: httpResponse)
            
        } catch let error as NetworkError {
            throw error
        } catch {
            throw NetworkError.networkFailure(error)
        }
    }
    
    // MARK: - Build Request
    
    private func buildRequest(
        endpoint: APIEndpoint,
        body: Encodable?,
        queryItems: [URLQueryItem]?,
        requiresAuth: Bool
    ) throws -> URLRequest {
        guard var urlComponents = URLComponents(string: environment.baseURL + endpoint.path) else {
            throw NetworkError.invalidURL
        }
        
        if let queryItems = queryItems, !queryItems.isEmpty {
            urlComponents.queryItems = queryItems
        }
        
        guard let url = urlComponents.url else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = endpoint.method.rawValue
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        
        if requiresAuth, let token = tokenStorage.accessToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        if let body = body {
            request.httpBody = try encoder.encode(body)
        }
        
        #if DEBUG
        logRequest(request)
        #endif
        
        return request
    }
    
    // MARK: - Handle Response
    
    private func handleResponse<T: Decodable>(data: Data, response: HTTPURLResponse) throws -> T {
        #if DEBUG
        logResponse(response, data: data)
        #endif
        
        switch response.statusCode {
        case 200...299:
            do {
                let decoded = try decoder.decode(T.self, from: data)
                return decoded
            } catch {
                throw NetworkError.decodingError(error)
            }
            
        case 401:
            throw NetworkError.unauthorized
            
        case 400...499:
            let errorMessage = try? decoder.decode(APIErrorResponse.self, from: data)
            throw NetworkError.serverError(
                statusCode: response.statusCode,
                message: errorMessage?.message
            )
            
        case 500...599:
            let errorMessage = try? decoder.decode(APIErrorResponse.self, from: data)
            throw NetworkError.serverError(
                statusCode: response.statusCode,
                message: errorMessage?.message ?? "Internal server error"
            )
            
        default:
            throw NetworkError.unknown
        }
    }
    
    // MARK: - Token Refresh
    
    private func refreshAccessToken() async throws {
        refreshLock.lock()
        defer { refreshLock.unlock() }
        
        guard !isRefreshing else { return }
        isRefreshing = true
        defer { isRefreshing = false }
        
        guard let refreshToken = tokenStorage.refreshToken else {
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        }
        
        let refreshRequest = RefreshTokenRequest(refreshToken: refreshToken)
        
        let urlRequest = try buildRequest(
            endpoint: .refreshToken,
            body: refreshRequest,
            queryItems: nil,
            requiresAuth: false
        )
        
        do {
            let (data, response) = try await session.data(for: urlRequest)
            guard let httpResponse = response as? HTTPURLResponse else {
                throw NetworkError.unknown
            }
            
            if httpResponse.statusCode == 200 || httpResponse.statusCode == 201 {
                let tokenResponse = try decoder.decode(RefreshTokenResponse.self, from: data)
                tokenStorage.accessToken = tokenResponse.accessToken
                tokenStorage.refreshToken = tokenResponse.refreshToken
            } else {
                tokenStorage.clearTokens()
                throw NetworkError.unauthorized
            }
        } catch {
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        }
    }
    
    // MARK: - Debug Logging
    
    #if DEBUG
    private func logRequest(_ request: URLRequest) {
        print("🌐 [\(request.httpMethod ?? "?")] \(request.url?.absoluteString ?? "")")
        if let headers = request.allHTTPHeaderFields {
            print("   Headers: \(headers)")
        }
        if let body = request.httpBody, let bodyString = String(data: body, encoding: .utf8) {
            print("   Body: \(bodyString)")
        }
    }
    
    private func logResponse(_ response: HTTPURLResponse, data: Data) {
        let emoji = (200...299).contains(response.statusCode) ? "✅" : "❌"
        print("\(emoji) [\(response.statusCode)] \(response.url?.absoluteString ?? "")")
        if let bodyString = String(data: data, encoding: .utf8) {
            let truncated = bodyString.prefix(500)
            print("   Response: \(truncated)")
        }
    }
    #endif
}

// MARK: - Auth Service

protocol AuthServiceProtocol {
    func login(email: String, password: String) async throws -> AuthResponse
    func register(email: String, password: String, name: String) async throws -> AuthResponse
    func logout()
    var isLoggedIn: Bool { get }
}

final class AuthService: AuthServiceProtocol {
    
    private let networkClient: NetworkClient
    
    init(networkClient: NetworkClient = .shared) {
        self.networkClient = networkClient
    }
    
    var isLoggedIn: Bool {
        return networkClient.tokenStorage.accessToken != nil
    }
    
    func login(email: String, password: String) async throws -> AuthResponse {
        let body = LoginRequest(email: email, password: password)
        let response: AuthResponse = try await networkClient.request(
            endpoint: .login,
            body: body,
            queryItems: nil,
            requiresAuth: false
        )
        
        networkClient.tokenStorage.accessToken = response.accessToken
        networkClient.tokenStorage.refreshToken = response.refreshToken
        
        return response
    }
    
    func register(email: String, password: String, name: String) async throws -> AuthResponse {
        let body = RegisterRequest(email: email, password: password, name: name)
        let response: AuthResponse = try await networkClient.request(
            endpoint: .register,
            body: body,
            queryItems: nil,
            requiresAuth: false
        )
        
        networkClient.tokenStorage.accessToken = response.accessToken
        networkClient.tokenStorage.refreshToken = response.refreshToken
        
        return response
    }
    
    func logout() {
        networkClient.tokenStorage.clearTokens()
    }
}

// MARK: - User Service

protocol UserServiceProtocol {
    func fetchCurrentUser() async throws -> User
    func fetchUsers(page: Int, perPage: Int) async throws -> UsersResponse
    func fetchUser(id: String) async throws -> User
    func updateProfile(name: String?, avatarURL: String?) async throws -> User
}

final class UserService: UserServiceProtocol {
    
    private let networkClient: NetworkClient
    
    init(networkClient: NetworkClient = .shared) {
        self.networkClient = networkClient
    }
    
    func fetchCurrentUser() async throws -> User {
        return try await networkClient.request(
            endpoint: .userProfile,
            body: nil,
            queryItems: nil,
            requiresAuth: true
        )
    }
    
    func fetchUsers(page: Int = 1, perPage: Int = 20) async throws -> UsersResponse {
        let queryItems = [
            URLQueryItem(name: "page", value: String(page)),
            URLQueryItem(name: "per_page", value: String(perPage))
        ]
        
        return try await networkClient.request(
            endpoint: .users,
            body: nil,
            queryItems: queryItems,
            requiresAuth: true
        )
    }
    
    func fetchUser(id: String) async throws -> User {
        return try await networkClient.request(
            endpoint: .user(id: id),
            body: nil,
            queryItems: nil,
            requiresAuth: true
        )
    }
    
    func updateProfile(name: String? = nil, avatarURL: String? = nil) async throws -> User {
        let body = UpdateProfileRequest(name: name, avatarURL: avatarURL)
        return try await networkClient.request(
            endpoint: .updateProfile,
            body: body,
            queryItems: nil,
            requiresAuth: true
        )
    }
}

// MARK: - Usage Example (ViewModel)

import Combine

@MainActor
final class UserViewModel: ObservableObject {
    
    @Published var currentUser: User?
    @Published var users: [User] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var isAuthenticated = false
    
    private let authService: AuthServiceProtocol
    private let userService: UserServiceProtocol
    
    init(
        authService: AuthServiceProtocol = AuthService(),
        userService: UserServiceProtocol = UserService()
    ) {
        self.authService = authService
        self.userService = userService
        self.isAuthenticated = authService.isLoggedIn
    }
    
    func login(email: String, password: String) async {
        isLoading = true
        errorMessage = nil
        
        do {
            let response = try await authService.login(email: email, password: password)
            currentUser = response.user
            isAuthenticated = true
        } catch let error as NetworkError {
            errorMessage = error.errorDescription
        } catch {
            errorMessage = error.localizedDescription
        }
        
        isLoading = false
    }
    
    func register(email: String, password: String, name: String) async {
        isLoading = true
        errorMessage = nil
        
        do {
            let response = try await authService.register(email: email, password: password, name: name)
            currentUser = response.user
            isAuthenticated = true
        } catch let error as NetworkError {
            errorMessage = error.errorDescription
        } catch {
            errorMessage = error.localizedDescription
        }
        
        isLoading = false
    }
    
    func fetchProfile() async {
        isLoading = true
        errorMessage = nil
        
        do {
            currentUser = try await userService.fetchCurrentUser()
        } catch let error as NetworkError {
            if case .unauthorized = error {
                logout()
            }
            errorMessage = error.errorDescription
        } catch {
            errorMessage = error.localizedDescription
        }
        
        isLoading = false
    }
    
    func fetchUsers(page: Int = 1) async {
        isLoading = true
        errorMessage = nil
        
        do {
            let response = try await userService.fetchUsers(page: page, perPage: 20)
            if page == 1 {
                users = response.users
            } else {
                users.append(contentsOf: response.users)
            }
        } catch let error as NetworkError {
            if case .unauthorized = error {
                logout()
            }
            errorMessage = error.errorDescription
        } catch {
            errorMessage = error.localizedDescription
        }
        
        isLoading = false
    }
    
    func updateProfile(name: String) async {
        isLoading = true
        errorMessage = nil
        
        do {
            currentUser = try await userService.updateProfile(name: name, avatarURL: nil)
        } catch let error as NetworkError {
            errorMessage = error.errorDescription
        } catch {
            errorMessage = error.localizedDescription
        }
        
        isLoading = false
    }
    
    func logout() {
        authService.logout()
        currentUser = nil
        users = []
        isAuthenticated = false
    }
}